  ('customs-7fec267e-moex-00346', 'customs-7fec267e', 'customs-7fec267e-moex-110-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '假設A國採行市場經濟體制，其紅酒市場的需求函數為：Q =120–3P，供給函數為：Q =5P–40， D S 市場處於均衡狀態。但在一次政權更迭之後，A國改採行指令型經濟體制，其生產與分配決策，例如 要生產什麼商品、生產多少、產出後如何分配，都由政府決定。若是A國採行指令型經濟體制後， 並沒有將紅酒納入生產分配計畫中，則紅酒廠商的生產者剩餘將如何變化？', '["從360增加到600", "從600減少到0", "從360減少到0", "不受影響"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:22+00:00", "source_pdf_sha1": "5bec6315ccf2", "answer_pdf_sha1": "c6a2f8035359", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "141", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
